import React, { useState, useRef, useEffect } from "react";

const BLOCK_TYPES = {
  INDICATOR: "indicator",
  CONDITION: "condition",
  ACTION: "action",
};

const INDICATORS = [
  { id: "rsi", label: "RSI", color: "#60A5FA" },
  { id: "macd", label: "MACD", color: "#60A5FA" },
  { id: "ema", label: "EMA", color: "#60A5FA" },
  { id: "sma", label: "SMA", color: "#60A5FA" },
  { id: "bollinger", label: "Bollinger", color: "#60A5FA" },
  { id: "volume", label: "Volume", color: "#60A5FA" },
  { id: "atr", label: "ATR", color: "#60A5FA" },
  { id: "price", label: "Price", color: "#60A5FA" },
];

const CONDITIONS = [
  { id: "crossesAbove", label: "Crosses Above", color: "#F59E0B" },
  { id: "crossesBelow", label: "Crosses Below", color: "#F59E0B" },
  { id: "greaterThan", label: "Greater Than", color: "#F59E0B" },
  { id: "lessThan", label: "Less Than", color: "#F59E0B" },
  { id: "equals", label: "Equals", color: "#F59E0B" },
];

const ACTIONS = [
  { id: "buy", label: "Buy", color: "#22C55E" },
  { id: "sell", label: "Sell", color: "#EF4444" },
  { id: "stopLoss", label: "Stop Loss", color: "#EF4444" },
  { id: "takeProfit", label: "Take Profit", color: "#22C55E" },
];

// Helper to generate unique IDs
let idCounter = 0;
function uniqueId() {
  return `block_${idCounter++}`;
}

function VisualStrategyBuilder() {
  const [blocks, setBlocks] = useState([]);
  const [connections, setConnections] = useState([]);
  const [draggingBlock, setDraggingBlock] = useState(null); // block id being dragged on canvas
  const [draggingNewBlock, setDraggingNewBlock] = useState(null); // block type from palette being dragged
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [connecting, setConnecting] = useState(null); // { fromBlockId, fromPort } or null
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const svgRef = useRef(null);
  const canvasRef = useRef(null);

  // Block port definitions
  // For simplicity:
  // Indicators: 1 output port (right)
  // Conditions: 1 input port (left), 1 output port (right)
  // Actions: 1 input port (left), no output port
  // Ports are named "in" or "out"

  // Drag handlers for palette blocks
  function onPaletteDragStart(e, blockType, blockId) {
    e.dataTransfer.setData("text/plain", JSON.stringify({ blockType, blockId }));
    setDraggingNewBlock({ blockType, blockId });
  }

  // Drag handlers for canvas blocks
  function onBlockMouseDown(e, id) {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setDraggingBlock(id);
    setDragOffset({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  }

  // Canvas mouse move for dragging blocks or drawing connections
  function onCanvasMouseMove(e) {
    const canvasRect = canvasRef.current.getBoundingClientRect();
    const x = e.clientX - canvasRect.left;
    const y = e.clientY - canvasRect.top;
    setMousePos({ x, y });

    if (draggingBlock) {
      setBlocks((blocks) =>
        blocks.map((b) =>
          b.id === draggingBlock
            ? { ...b, x: x - dragOffset.x, y: y - dragOffset.y }
            : b
        )
      );
    }
  }

  // Canvas mouse up to drop blocks or finish connections
  function onCanvasMouseUp(e) {
    if (draggingNewBlock) {
      // Add new block at mouse position
      const canvasRect = canvasRef.current.getBoundingClientRect();
      const x = e.clientX - canvasRect.left - 75; // center block (block width 150)
      const y = e.clientY - canvasRect.top - 20; // center block (block height 40)
      const newBlock = {
        id: uniqueId(),
        type:
          INDICATORS.find((b) => b.id === draggingNewBlock.blockId)
            ? BLOCK_TYPES.INDICATOR
            : CONDITIONS.find((b) => b.id === draggingNewBlock.blockId)
            ? BLOCK_TYPES.CONDITION
            : BLOCK_TYPES.ACTION,
        blockId: draggingNewBlock.blockId,
        label:
          INDICATORS.find((b) => b.id === draggingNewBlock.blockId)?.label ||
          CONDITIONS.find((b) => b.id === draggingNewBlock.blockId)?.label ||
          ACTIONS.find((b) => b.id === draggingNewBlock.blockId)?.label,
        color:
          INDICATORS.find((b) => b.id === draggingNewBlock.blockId)?.color ||
          CONDITIONS.find((b) => b.id === draggingNewBlock.blockId)?.color ||
          ACTIONS.find((b) => b.id === draggingNewBlock.blockId)?.color,
        x,
        y,
      };
      setBlocks((blocks) => [...blocks, newBlock]);
      setDraggingNewBlock(null);
    }
    if (draggingBlock) {
      setDraggingBlock(null);
    }
    if (connecting) {
      // Try to connect to port under mouse
      const target = getPortAtPosition(mousePos.x, mousePos.y);
      if (
        target &&
        target.blockId !== connecting.fromBlockId &&
        target.portType === "in"
      ) {
        // Prevent duplicate connections from same output to same input
        const exists = connections.find(
          (c) =>
            c.fromBlockId === connecting.fromBlockId &&
            c.toBlockId === target.blockId
        );
        if (!exists) {
          setConnections((conns) => [
            ...conns,
            {
              id: `conn_${Date.now()}`,
              fromBlockId: connecting.fromBlockId,
              toBlockId: target.blockId,
            },
          ]);
        }
      }
      setConnecting(null);
    }
  }

  // Cancel drag on leave canvas
  function onCanvasMouseLeave() {
    if (draggingNewBlock) setDraggingNewBlock(null);
    if (draggingBlock) setDraggingBlock(null);
    if (connecting) setConnecting(null);
  }

  // Get port positions for a block
  // Returns { in: {x,y}, out: {x,y} } or null if no such port
  function getPorts(block) {
    // Block size: width 150, height 40
    const width = 150;
    const height = 40;
    const x = block.x;
    const y = block.y;
    if (block.type === BLOCK_TYPES.INDICATOR) {
      return {
        out: { x: x + width, y: y + height / 2 },
      };
    }
    if (block.type === BLOCK_TYPES.CONDITION) {
      return {
        in: { x: x, y: y + height / 2 },
        out: { x: x + width, y: y + height / 2 },
      };
    }
    if (block.type === BLOCK_TYPES.ACTION) {
      return {
        in: { x: x, y: y + height / 2 },
      };
    }
    return {};
  }

  // Find port under mouse position (within 10px radius)
  // Returns { blockId, portType } or null
  function getPortAtPosition(x, y) {
    for (const block of blocks) {
      const ports = getPorts(block);
      for (const portType in ports) {
        const p = ports[portType];
        const dx = p.x - x;
        const dy = p.y - y;
        if (dx * dx + dy * dy < 100) {
          return { blockId: block.id, portType };
        }
      }
    }
    return null;
  }

  // Start connecting from output port
  function onPortMouseDown(e, blockId, portType) {
    e.stopPropagation();
    if (portType === "out") {
      setConnecting({ fromBlockId: blockId });
    }
  }

  // Remove connection on right click
  function onConnectionContextMenu(e, id) {
    e.preventDefault();
    setConnections((conns) => conns.filter((c) => c.id !== id));
  }

  // Toolbar button handlers
  function onSave() {
    const data = { blocks, connections };
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "strategy.json";
    a.click();
    URL.revokeObjectURL(url);
  }

  function onLoad() {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = "application/json";
    input.onchange = (e) => {
      const file = e.target.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (ev) => {
        try {
          const data = JSON.parse(ev.target.result);
          if (data.blocks && data.connections) {
            setBlocks(data.blocks);
            setConnections(data.connections);
          }
        } catch {}
      };
      reader.readAsText(file);
    };
    input.click();
  }

  function onBacktest() {
    alert("Backtest started (mock)");
  }

  function onClear() {
    setBlocks([]);
    setConnections([]);
  }

  // Generate strategy JSON for right panel
  function generateStrategyJSON() {
    return JSON.stringify({ blocks, connections }, null, 2);
  }

  // Block component
  function Block({ block }) {
    const width = 150;
    const height = 40;
    const ports = getPorts(block);

    return (
      <g
        transform={`translate(${block.x},${block.y})`}
        style={{ cursor: "move", userSelect: "none" }}
        onMouseDown={(e) => onBlockMouseDown(e, block.id)}
      >
        <rect
          width={width}
          height={height}
          rx={6}
          ry={6}
          fill={block.color}
          stroke="#1F2A37"
          strokeWidth={2}
        />
        <text
          x={width / 2}
          y={height / 2 + 5}
          fill="#E5E7DB"
          fontFamily="'JetBrains Mono', monospace"
          fontSize={14}
          fontWeight="600"
          textAnchor="middle"
          pointerEvents="none"
          style={{ userSelect: "none" }}
        >
          {block.label}
        </text>
        {/* Ports */}
        {ports.in && (
          <circle
            cx={ports.in.x - block.x}
            cy={ports.in.y - block.y}
            r={6}
            fill="#0F1620"
            stroke="#F59E0B"
            strokeWidth={2}
            onMouseDown={(e) => e.stopPropagation()}
            onClick={(e) => e.stopPropagation()}
          />
        )}
        {ports.out && (
          <circle
            cx={ports.out.x - block.x}
            cy={ports.out.y - block.y}
            r={6}
            fill="#0F1620"
            stroke="#F59E0B"
            strokeWidth={2}
            style={{ cursor: "crosshair" }}
            onMouseDown={(e) => onPortMouseDown(e, block.id, "out")}
          />
        )}
      </g>
    );
  }

  // Connection component (line between ports)
  function Connection({ connection }) {
    const fromBlock = blocks.find((b) => b.id === connection.fromBlockId);
    const toBlock = blocks.find((b) => b.id === connection.toBlockId);
    if (!fromBlock || !toBlock) return null;
    const fromPorts = getPorts(fromBlock);
    const toPorts = getPorts(toBlock);
    if (!fromPorts.out || !toPorts.in) return null;

    const startX = fromPorts.out.x;
    const startY = fromPorts.out.y;
    const endX = toPorts.in.x;
    const endY = toPorts.in.y;

    // Draw a smooth cubic bezier curve
    const deltaX = Math.max(40, Math.abs(endX - startX) / 2);
    const path = `M${startX},${startY} C${startX + deltaX},${startY} ${endX - deltaX},${endY} ${endX},${endY}`;

    return (
      <path
        d={path}
        stroke="#F59E0B"
        strokeWidth={3}
        fill="none"
        onContextMenu={(e) => onConnectionContextMenu(e, connection.id)}
        style={{ cursor: "context-menu" }}
      />
    );
  }

  // Palette block item
  function PaletteBlock({ block, type }) {
    return (
      <div
        draggable
        onDragStart={(e) => onPaletteDragStart(e, type, block.id)}
        style={{
          userSelect: "none",
          marginBottom: 8,
          padding: "6px 12px",
          borderRadius: 6,
          backgroundColor: block.color,
          color: "#0F1620",
          fontWeight: "600",
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: 14,
          cursor: "grab",
          textAlign: "center",
          boxShadow: `0 0 6px ${block.color}`,
        }}
        title={`Drag to canvas: ${block.label}`}
      >
        {block.label}
      </div>
    );
  }

  return (
    <div
      style={{
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        backgroundColor: "#0B0F14",
        color: "#E5E7DB",
        fontFamily: "'JetBrains Mono', monospace",
        userSelect: "none",
      }}
    >
      {/* Toolbar */}
      <div
        style={{
          height: 48,
          backgroundColor: "#0F1620",
          borderBottom: "1px solid #1F2A37",
          display: "flex",
          alignItems: "center",
          padding: "0 12px",
          gap: 12,
        }}
      >
        <button
          onClick={onSave}
          style={{
            backgroundColor: "#1F2A37",
            border: "none",
            color: "#E5E7DB",
            padding: "6px 12px",
            borderRadius: 6,
            cursor: "pointer",
            fontFamily: "'JetBrains Mono', monospace",
            fontWeight: "600",
          }}
          title="Save strategy JSON"
        >
          Save
        </button>
        <button
          onClick={onLoad}
          style={{
            backgroundColor: "#1F2A37",
            border: "none",
            color: "#E5E7DB",
            padding: "6px 12px",
            borderRadius: 6,
            cursor: "pointer",
            fontFamily: "'JetBrains Mono', monospace",
            fontWeight: "600",
          }}
          title="Load strategy JSON"
        >
          Load
        </button>
        <button
          onClick={onBacktest}
          style={{
            backgroundColor: "#1F2A37",
            border: "none",
            color: "#E5E7DB",
            padding: "6px 12px",
            borderRadius: 6,
            cursor: "pointer",
            fontFamily: "'JetBrains Mono', monospace",
            fontWeight: "600",
          }}
          title="Run backtest"
        >
          Backtest
        </button>
        <button
          onClick={onClear}
          style={{
            backgroundColor: "#1F2A37",
            border: "none",
            color: "#E5E7DB",
            padding: "6px 12px",
            borderRadius: 6,
            cursor: "pointer",
            fontFamily: "'JetBrains Mono', monospace",
            fontWeight: "600",
          }}
          title="Clear canvas"
        >
          Clear
        </button>
      </div>

      {/* Main content */}
      <div style={{ flex: 1, display: "flex", height: "calc(100vh - 48px)" }}>
        {/* Left Sidebar */}
        <div
          style={{
            width: 180,
            backgroundColor: "#0F1620",
            borderRight: "1px solid #1F2A37",
            padding: 12,
            overflowY: "auto",
          }}
        >
          <div style={{ marginBottom: 16 }}>
            <div
              style={{
                fontWeight: "700",
                fontSize: 16,
                marginBottom: 8,
                color: "#F59E0B",
              }}
            >
              Indicators
            </div>
            {INDICATORS.map((b) => (
              <PaletteBlock key={b.id} block={b} type={BLOCK_TYPES.INDICATOR} />
            ))}
          </div>
          <div style={{ marginBottom: 16 }}>
            <div
              style={{
                fontWeight: "700",
                fontSize: 16,
                marginBottom: 8,
                color: "#F59E0B",
              }}
            >
              Conditions
            </div>
            {CONDITIONS.map((b) => (
              <PaletteBlock key={b.id} block={b} type={BLOCK_TYPES.CONDITION} />
            ))}
          </div>
          <div>
            <div
              style={{
                fontWeight: "700",
                fontSize: 16,
                marginBottom: 8,
                color: "#F59E0B",
              }}
            >
              Actions
            </div>
            {ACTIONS.map((b) => (
              <PaletteBlock key={b.id} block={b} type={BLOCK_TYPES.ACTION} />
            ))}
          </div>
        </div>

        {/* Canvas */}
        <div
          ref={canvasRef}
          style={{
            flex: 1,
            position: "relative",
            backgroundColor: "#0B0F14",
            overflow: "hidden",
            cursor: draggingBlock ? "grabbing" : "default",
          }}
          onDragOver={(e) => e.preventDefault()}
          onDrop={onCanvasMouseUp}
          onMouseMove={onCanvasMouseMove}
          onMouseUp={onCanvasMouseUp}
          onMouseLeave={onCanvasMouseLeave}
          onClick={() => {
            if (connecting) setConnecting(null);
          }}
        >
          <svg
            ref={svgRef}
            style={{ width: "100%", height: "100%", position: "absolute", top: 0, left: 0 }}
          >
            {/* Connections */}
            {connections.map((conn) => (
              <Connection key={conn.id} connection={conn} />
            ))}

            {/* Connection line while connecting */}
            {connecting && (
              (() => {
                const fromBlock = blocks.find((b) => b.id === connecting.fromBlockId);
                if (!fromBlock) return null;
                const fromPorts = getPorts(fromBlock);
                if (!fromPorts.out) return null;
                const startX = fromPorts.out.x;
                const startY = fromPorts.out.y;
                const endX = mousePos.x;
                const endY = mousePos.y;
                const deltaX = Math.max(40, Math.abs(endX - startX) / 2);
                const path = `M${startX},${startY} C${startX + deltaX},${startY} ${endX - deltaX},${endY} ${endX},${endY}`;
                return (
                  <path
                    d={path}
                    stroke="#F59E0B"
                    strokeWidth={3}
                    fill="none"
                    pointerEvents="none"
                    strokeDasharray="6 4"
                  />
                );
              })()
            )}

            {/* Blocks */}
            {blocks.map((block) => (
              <Block key={block.id} block={block} />
            ))}
          </svg>
        </div>

        {/* Right Panel */}
        <div
          style={{
            width: 320,
            backgroundColor: "#0F1620",
            borderLeft: "1px solid #1F2A37",
            padding: 12,
            overflowY: "auto",
            fontSize: 13,
            whiteSpace: "pre-wrap",
            fontFamily: "'JetBrains Mono', monospace",
            color: "#E5E7DB",
          }}
          tabIndex={0}
          aria-label="Generated strategy JSON"
        >
          {generateStrategyJSON()}
        </div>
      </div>
    </div>
  );
}

export default VisualStrategyBuilder;
